function initPreloader() {
  window.scrollTo(0, 0);
  const preloader = document.querySelector('[preloader]');
  if (!preloader) {
    initPageTransitions();
    return;
  }

  const hasVisited = sessionStorage.getItem('hasVisited');
  const duration = hasVisited ? 1 : 3;
  const delay = duration * 1000;

  sessionStorage.setItem('hasVisited', 'true');

  initPreloaderAnimation(duration);
  initPreloaderWindow(duration);

  document.body.style.overflow = 'hidden';
  document.body.setAttribute('data-lenis-prevent', '');

  setTimeout(() => {
    initGlobe();
  }, 900);

  setTimeout(() => {
    initPageTransitions();

    gsap.to(preloader, {
      autoAlpha: 0,
      duration: 0.6,
      delay: 0.4,
      ease: 'Out',
      onComplete: () => {
        preloader.style.display = 'none';
        document.body.style.overflow = '';
        document.body.removeAttribute('data-lenis-prevent');
      }
    });
  }, delay);
}

function initPageTransitions() {
  const transitionOffset = 0;

  function delay(n = transitionOffset) {
    return new Promise(res => setTimeout(res, n));
  }

  function killAllScrollTriggers() {
    ScrollTrigger.getAll().forEach(t => t.kill());
  }

  async function commonLeaveBeforeOffset({ current }) {
    return gsap.to(current.container, {
      opacity: 0,
      duration: 0.6,
      delay: 0,
      ease: "InOut"
    });
  }

  async function commonLeaveAfterOffset({ current }) {
    lenis && lenis.destroy();
    killAllScrollTriggers();
    current.container.remove();
    await delay();
  }

  async function commonEnter({ next }) {
    gsap.set(next.container, { opacity: 0 });
    return gsap.to(next.container, {
      opacity: 1,
      duration: 0.6,
      delay: 0,
      ease: "InOut"
    });
  }

  async function commonBeforeEnter({ next }) {
    initPreloaderHide();
    requestAnimationFrame(() => {
      lenis && lenis.scrollTo(0, { immediate: true });
    });
    killAllScrollTriggers();
    initScripts();
    ScrollTrigger.refresh();
  }

  async function commonAfterEnter(data) {
    initResetWebflow(data);
    setTimeout(() => {
      initGlobe();
    }, 1000);
  }

  // Barba.js
  barba.init({
    sync: false,
    debug: true,
    transitions: [{
      name: 'slide-fade',

      once(data) {
        initScripts();
      },

      async leave(data) {
        await commonLeaveBeforeOffset(data);
        await commonLeaveAfterOffset(data);
      },

      async enter(data) {
        await commonEnter(data);
      },

      async beforeEnter(data) {
        await commonBeforeEnter(data);
      },

      async afterEnter(data) {
        await commonAfterEnter(data);
      }
    }]
  });
}

