function initPreloaderAnimation(duration) {
  const targetId = "preloader";
  const preloader = document.querySelector('[preloader]');

  if (preloader) preloader.classList.remove('bg-grad');

  splitTextSetup(targetId);
  animateTextReveal(targetId, "in");

  setTimeout(() => {
    animateTextReveal(targetId, "out");
  }, duration * 1000);

  const bg = document.querySelector('[preloader-bg]');
  if (bg) {
    gsap.fromTo(bg, { "--mask-size": "100% 200%", "--mask-y": "0%" }, {
      "--mask-size": "100% 200%",
      "--mask-y": "200%",
      duration: 1.2,
      delay: duration - 0.4,
      ease: 'Out'
    });
  }
}

