function initLenis() {
  if (lenis) {
    lenis.destroy();
    lenis = null;
  }

  // Global lenis scroll
  lenis = new Lenis({
    wrapper: window,
    duration: 1.2,
    smoothWheel: true,
    smoothTouch: false,
    touchMultiplier: 2,
    easing: t => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
    useOverscroll: true,
    useControls: true,
    useAnchor: true,
    useRaf: true,
    infinite: false
  });
  // https://www.desmos.com/calculator/brs54l4xou

  lenis.on('scroll', ScrollTrigger.update);
  gsap.ticker.add((time) => lenis.raf(time * 1000));
  gsap.ticker.lagSmoothing(0);

  // Local lenis scroll
  document.querySelectorAll('[data-lenis-scroll]').forEach(container => {
    const localLenis = new Lenis({
      wrapper: container,
      duration: 0.6,
      smoothWheel: true,
      smoothTouch: false,
      easing: t => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      useOverscroll: false,
      useControls: false,
      useAnchor: false,
      useRaf: false,
      infinite: false
    });

    function raf(time) {
      localLenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);
  });
}

function splitTextSetup(targetId) {
  const els = document.querySelectorAll(`[data-reveal-text="${targetId}"]`)
  els.forEach(el => {
    if (el.__splitDone) return

    el.innerHTML = el.innerHTML.replace(/(<br\s*\/?>\s*){2}/g, "$1&zwnj;$1")

    const typeAttr = el.getAttribute('data-split-text')
    const type = ['lines', 'words', 'chars'].includes(typeAttr) ? typeAttr : 'lines'

    const st = new SplitText(el, {
      type,
      linesClass: 'line',
      wordsClass: 'word',
      charsClass: 'char'
    })

    el.__splitType = type
    el.__targets = type === 'words' ? st.words : type === 'chars' ? st.chars : st.lines
    el.__revealTL = null
    el.__splitDone = true

    gsap.set(el, { visibility: 'visible' })
  })
}

function killTextReveal(targetId) {
  const els = document.querySelectorAll(`[data-reveal-text="${targetId}"]`)
  els.forEach(el => {
    if (el.__revealTL) {
      el.__revealTL.kill()
      el.__revealTL = null
    }
    const targets = el.__targets || []
    if (targets.length) gsap.killTweensOf(targets)
  })
}

function animateTextReveal(targetId, mode = 'in') {
  const els = document.querySelectorAll(`[data-reveal-text="${targetId}"]`)
  els.forEach(el => {
    const type = el.__splitType || el.getAttribute('data-split-text') || 'lines'
    const targets = el.__targets || el.querySelectorAll(
      type === 'words' ? '.word' : type === 'chars' ? '.char' : '.line'
    )
    if (!targets || !targets.length) return

    let tl = el.__revealTL
    if (tl) tl.kill()

    tl = gsap.timeline({ defaults: { overwrite: 'auto' } })
    el.__revealTL = tl

    if (type === 'lines') {
      if (mode === 'in') {
        tl.fromTo(targets, { filter: "blur(36px)", opacity: 0 }, {
          filter: "blur(0px)",
          opacity: 1,
          duration: 1,
          stagger: 0.08,
          ease: 'Out'
        })
      } else {
        tl.to(targets, {
          filter: "blur(36px)",
          opacity: 0,
          duration: 0.6,
          stagger: 0.02,
          ease: 'In'
        })
      }
    }

    if (type === 'words') {
      if (mode === 'in') {
        tl.fromTo(targets, { opacity: 0, rotateX: 90 }, {
          opacity: 1,
          rotateX: 0,
          transformOrigin: "center bottom",
          duration: 1,
          delay: 0.2,
          stagger: 0.075,
          ease: 'Out'
        })
      } else {
        tl.to(targets, {
          opacity: 0,
          rotateX: 90,
          transformOrigin: "center bottom",
          duration: 0.6,
          stagger: 0.05,
          ease: 'Out'
        })
      }
    }

    if (type === 'chars') {
      if (mode === 'in') {
        tl.fromTo(targets, { opacity: 0, rotateY: 90 }, {
          opacity: 1,
          rotateY: 0,
          transformOrigin: "center center",
          duration: 1,
          delay: 0.2,
          stagger: 0.025,
          ease: 'Out'
        })
      } else {
        tl.to(targets, {
          opacity: 0,
          rotateY: 90,
          transformOrigin: "center center",
          duration: 0.6,
          stagger: 0.025,
          ease: 'Out'
        })
      }
    }
  })
}

function initScrollTriggerRefresh() {
  if (!window.gsap || !window.ScrollTrigger) return;

  var currentScroll = window.pageYOffset || document.documentElement.scrollTop || 0;

  var animStates = [];
  var seen = new Set();
  ScrollTrigger.getAll().forEach(function (st) {
    var a = st.animation;
    if (!a) return;
    if (seen.has(a)) return;
    seen.add(a);
    animStates.push({
      anim: a,
      paused: a.paused(),
      totalProgress: a.totalProgress()
    });
  });

  ScrollTrigger.refresh();

  for (var i = 0; i < animStates.length; i++) {
    var s = animStates[i];
    var a = s.anim;
    if (!a) continue;
    a.totalProgress(s.totalProgress, true);
    if (s.paused) {
      a.pause();
    } else {
      a.play();
    }
  }

  if (typeof window.scrollTo === 'function') {
    window.scrollTo(0, currentScroll);
  }

  if (gsap.ticker && typeof gsap.ticker.flush === 'function') {
    gsap.ticker.flush();
  }
}

function initThemeChange() {
  const themedElements = document.querySelectorAll("[theme]");

  function createTrigger(section, addClass, removeClass) {
    themedElements.forEach(el => {
      const height = el.offsetHeight;

      ScrollTrigger.create({
        trigger: section,
        start: () => `top top+=${height / 2}`,
        end: () => `top top+=${height / 2 + 1}`,
        onEnter: () => {
          el.classList.add(addClass);
          el.classList.remove(removeClass);
        },
        onLeaveBack: () => {
          el.classList.remove(addClass);
          el.classList.add(removeClass);
        },
        markers: false
      });

      ScrollTrigger.create({
        trigger: section,
        start: () => `bottom top+=${height / 2}`,
        end: () => `bottom top+=${height / 2 + 1}`,
        onEnter: () => {
          el.classList.remove(addClass);
          el.classList.add(removeClass);
        },
        onLeaveBack: () => {
          el.classList.add(addClass);
          el.classList.remove(removeClass);
        },
        markers: false
      });
    });
  }

  document.querySelectorAll('[bg="color"]').forEach(section => {
    createTrigger(section, 'theme_on-color', 'theme_on-light');
  });

  document.querySelectorAll('[bg="light"]').forEach(section => {
    createTrigger(section, 'theme_on-light', 'theme_on-color');
  });
}

function initCurrentTime() {
  // Current time
  const TIMEZONE = 'Asia/Dubai';

  function updateClock() {
    const clockElements = document.querySelectorAll('[clock="time"]');
    if (!clockElements.length) return;

    const now = new Date();

    const formatter = new Intl.DateTimeFormat('en-GB', {
      timeZone: TIMEZONE,
      hour: '2-digit',
      minute: '2-digit',
      // second: '2-digit',
      hour12: false
    });

    const timeString = formatter.format(now);

    clockElements.forEach(el => {
      el.textContent = timeString;
    });
  }

  setInterval(updateClock, 1000);
  updateClock();
}

function initFavicon() {
  ScrollTrigger.matchMedia({
    [`(min-width: ${breakPoint}px)`]: function () {
      var srcFrames = [
        '../../cdn.prod.website-files.com/68b57ef5ef86011d9b251e8e/68d5b157ea29e138590eb3fe_fav_32x32.png',
        '../../cdn.prod.website-files.com/68b57ef5ef86011d9b251e8e/68d5b1f46b79fff0e28ec9d6_fav-2_32x32.png'
      ];

      var link = document.querySelector("link[rel*='icon']") || document.createElement(
        'link');
      link.rel = 'icon';
      link.type = 'image/png';
      if (!link.parentNode) document.head.appendChild(link);

      var objectFrames = [];
      var current = 0;
      var intervalId = null;

      function fetchAsBlobURL(url) {
        return fetch(url, { mode: 'cors', cache: 'force-cache' })
          .then(function (r) { return r.ok ? r.blob() : Promise.reject(r.status); })
          .then(function (blob) { return URL.createObjectURL(blob); });
      }

      function preloadFrames() {
        return Promise.all(
          srcFrames.map(function (u) {
            return fetchAsBlobURL(u).catch(function () { return u; });
          })
        ).then(function (urls) {
          objectFrames = urls;
          link.href = objectFrames[0];
        });
      }

      function startAnimation() {
        if (intervalId || objectFrames.length === 0) return;
        intervalId = setInterval(function () {
          link.href = objectFrames[current];
          current = (current + 1) % objectFrames.length;
        }, 100);
      }

      function stopAnimation() {
        if (!intervalId) return;
        clearInterval(intervalId);
        intervalId = null;
      }

      document.addEventListener('visibilitychange', function () {
        if (document.hidden) startAnimation();
        else stopAnimation();
      });

      window.addEventListener('beforeunload', function () {
        objectFrames.forEach(function (u) {
          if (u && u.startsWith('blob:')) URL.revokeObjectURL(u);
        });
      });

      preloadFrames();
    }
  });
}

