function initPopups() {
  // Open pop-ups
  document.querySelectorAll('[pop-up-open]').forEach(btn => {
    const id = btn.getAttribute('pop-up-open');
    const popup = document.querySelector(`[pop-up="${id}"]`);
    const popupMain = document.querySelector(`[pop-up-main="${id}"]`);
    const popupSuccess = document.querySelector(`[pop-up-success="${id}"]`);
    const btnContainer = document.querySelector(`[pop-up-btn-c="${id}"]`);
    const overlay = document.querySelector(`[pop-up-over="${id}"]`);
    const openBtns = document.querySelectorAll(`[pop-up-open="${id}"]`);
    const closeBtns = document.querySelectorAll(`[pop-up-close="${id}"]`);

    if (!popup || !overlay) return;

    btn.addEventListener('click', () => {
      gsap.killTweensOf([popup, popupMain, popupSuccess, btnContainer, overlay, openBtns,
        closeBtns
      ]);

      gsap.set(popup, { display: 'block' });

      gsap.fromTo(popupMain, { yPercent: 110 }, {
        yPercent: 0,
        duration: 1,
        ease: "Out"
      });

      gsap.fromTo(popupSuccess, { y: '110vh', rotate: 0 }, {
        y: '0',
        rotate: 0,
        duration: 1,
        ease: "Out"
      });

      gsap.to(btnContainer, {
        y: () => {
          const em = parseFloat(getComputedStyle(popupMain).fontSize);
          return -(popupMain.offsetHeight - 1.667 * em) + "px";
        },
        duration: 1,
        ease: "Out"
      });

      gsap.fromTo(openBtns, { x: "0em", display: "flex" }, {
        x: "3.333em",
        duration: 1,
        ease: "Out",
        onUpdate: function () {
          if (this.progress() >= 0) {
            openBtns.forEach(btn => btn.style.display = "none");
          }
        }
      });

      gsap.fromTo(closeBtns, { x: "-3.333em", display: "none" }, {
        x: "0em",
        duration: 1,
        ease: "Out",
        onUpdate: function () {
          if (this.progress() >= 0) {
            closeBtns.forEach(btn => btn.style.display = "flex");
          }
        }
      });

      gsap.fromTo(overlay, { opacity: 0 }, {
        opacity: 1,
        duration: 1,
        ease: "Out"
      });

      document.body.style.overflow = 'hidden';
      document.body.setAttribute('data-lenis-prevent', '');
    });
  });

  // Close pop-ups
  document.querySelectorAll('[pop-up-close]').forEach(btn => {
    const id = btn.getAttribute('pop-up-close');
    const popup = document.querySelector(`[pop-up="${id}"]`);
    const popupMain = document.querySelector(`[pop-up-main="${id}"]`);
    const popupSuccess = document.querySelector(`[pop-up-success="${id}"]`);
    const btnContainer = document.querySelector(`[pop-up-btn-c="${id}"]`);
    const overlay = document.querySelector(`[pop-up-over="${id}"]`);
    const openBtns = document.querySelectorAll(`[pop-up-open="${id}"]`);
    const closeBtns = document.querySelectorAll(`[pop-up-close="${id}"]`);

    if (!popup || !overlay) return;

    btn.addEventListener('click', () => {
      gsap.killTweensOf([popup, popupMain, popupSuccess, btnContainer, overlay, openBtns,
        closeBtns
      ]);

      gsap.to(popupMain, {
        yPercent: 110,
        duration: 1,
        ease: "Out",
        onComplete: () => popup.style.display = 'none'
      });

      gsap.to(popupSuccess, {
        y: '110vh',
        rotate: 25,
        duration: 1,
        ease: "In"
      });

      gsap.to(btnContainer, {
        y: 0,
        duration: 1,
        ease: "Out"
      });

      gsap.to(openBtns, {
        x: "0em",
        duration: 1,
        ease: "Out",
        onUpdate: function () {
          if (this.progress() >= 0) {
            openBtns.forEach(btn => btn.style.display = "flex");
          }
        }
      });

      gsap.to(closeBtns, {
        x: "-3.333em",
        duration: 1,
        ease: "Out",
        onUpdate: function () {
          if (this.progress() >= 0) {
            closeBtns.forEach(btn => btn.style.display = "none");
          }
        }
      });

      gsap.to(overlay, {
        opacity: 0,
        duration: 1,
        ease: "Out"
      });

      document.body.style.overflow = '';
      document.body.removeAttribute('data-lenis-prevent');
    });
  });
}

function initMenu() {
  ScrollTrigger.matchMedia({
    [`(max-width: ${breakPoint - 1}px)`]: function () {
      const openState = {};

      document.querySelectorAll('[menu-btn]').forEach(btn => {
        const id = btn.getAttribute('menu-btn');
        const popup = document.querySelector(`[menu="${id}"]`);
        const popupList = document.querySelector(`[menu-list="${id}"]`);
        const overlay = document.querySelector(`[menu-over="${id}"]`);
        const icon1 = document.querySelector(`[menu-ico-1="${id}"]`);
        const icon2 = document.querySelector(`[menu-ico-2="${id}"]`);
        const icon3 = document.querySelector(`[menu-ico-3="${id}"]`);
        const header = document.querySelector('.header_c');
        const btnCloses = document.querySelectorAll(`[menu-close="${id}"]`);
        if (!popup || !overlay || !header || !popupList) return;

        const listItems = Array.from(popupList.children).filter(el => el.nodeType === 1);
        if (!(id in openState)) openState[id] = false;

        let closeTween = null;

        function openMenu() {
          if (closeTween) {
            closeTween.kill();
            closeTween = null;
          }
          gsap.killTweensOf([popup, overlay, icon1, icon2, icon3, ...listItems]);

          openState[id] = true;

          document.body.style.overflow = 'hidden';
          document.body.setAttribute('data-lenis-prevent', '');
          header.classList.add('theme_on-color');

          gsap.set(popup, { display: 'block' });
          gsap.set(listItems, { xPercent: -50, opacity: 0 });

          gsap.set(overlay, { opacity: 0, display: 'block' });
          gsap.to(overlay, { opacity: 1, duration: 0.6, ease: 'Out' });

          icon1 && gsap.to(icon1, {
            rotate: 45,
            xPercent: -20,
            yPercent: 20,
            duration: 0.6,
            ease: 'InOut'
          });
          icon3 && gsap.to(icon3, {
            rotate: -45,
            xPercent: -20,
            yPercent: -20,
            duration: 0.6,
            ease: 'InOut'
          });
          icon2 && gsap.to(icon2, { scaleX: 0, duration: 0.6, ease: 'InOut' });

          gsap.to(listItems, {
            xPercent: 0,
            opacity: 1,
            duration: 0.6,
            ease: 'Out',
            stagger: 0.1,
            overwrite: 'auto'
          });
        }

        function closeMenu() {
          gsap.killTweensOf([popup, overlay, icon1, icon2, icon3, ...listItems]);

          openState[id] = false;

          closeTween = gsap.to(listItems, {
            xPercent: 0,
            opacity: 0,
            duration: 0.6,
            ease: 'Out',
            stagger: 0.1,
            overwrite: 'auto',
            onComplete: () => {
              closeTween = null;
              if (openState[id]) return;
              popup.style.display = 'none';
              document.body.style.overflow = '';
              document.body.removeAttribute('data-lenis-prevent');
              header.classList.remove('theme_on-color');
            }
          });

          gsap.to(overlay, {
            opacity: 0,
            duration: 0.6,
            ease: 'In',
            onComplete: () => overlay.style.display = 'none'
          });

          icon1 && gsap.to(icon1, {
            rotate: 0,
            xPercent: 0,
            yPercent: 0,
            duration: 0.6,
            ease: 'InOut'
          });
          icon3 && gsap.to(icon3, {
            rotate: 0,
            xPercent: 0,
            yPercent: 0,
            duration: 0.6,
            ease: 'InOut'
          });
          icon2 && gsap.to(icon2, { scaleX: 1, duration: 0.6, ease: 'InOut' });
        }

        btn.addEventListener('click', () => {
          if (!openState[id]) openMenu();
          else closeMenu();
        });

        btnCloses.forEach(closeBtn => {
          closeBtn.addEventListener('click', () => {
            if (openState[id]) closeMenu();
          });
        });
      });
    }
  });
}

function initGlobe() {
  ScrollTrigger.matchMedia({
    [`(min-width: ${breakPoint}px)`]: function () {
      const container = document.querySelector('[globe-container]');
      if (!container || typeof Globe !== 'function') return;

      const N = 10;

      const arcsData = [...Array(N).keys()].map(() => ({
        startLat: (Math.random() - 0.5) * 180,
        startLng: (Math.random() - 0.5) * 360,
        endLat: (Math.random() - 0.5) * 180,
        endLng: (Math.random() - 0.5) * 360,
        color: ['#7A716E', '#7A716E']
      }));

      const endpoints = arcsData.flatMap(a => ([
        { lat: a.startLat, lng: a.startLng },
        { lat: a.endLat, lng: a.endLng }
      ]));

      const globe = Globe()(container)
        .globeImageUrl(
          '../../cdn.prod.website-files.com/68b57ef5ef86011d9b251e8e/68ba0382a28da03b24642636_globe-map.svg'
        )
        .showAtmosphere(false)
        .backgroundColor('rgba(0,0,0,0)')
        .width(container.offsetWidth)
        .height(container.offsetHeight)

        // Lines
        .arcsData(arcsData)
        .arcColor('color')
        .arcStroke(0.5)
        .arcDashLength(0.6)
        .arcDashGap(0.2)
        .arcDashAnimateTime(8000)
        .arcsTransitionDuration(0)

        // Dots
        .pointsData(endpoints)
        .pointColor(() => '#7A716E')
        .pointAltitude(0)
        .pointRadius(0.5)
        .pointResolution(8)
        .pointsTransitionDuration(0);

      const mat = globe.globeMaterial && globe.globeMaterial();
      if (mat) {
        mat.shininess = 0;
        if (window.THREE) mat.specular = new THREE.Color(0x000000);
        mat.needsUpdate = true;
      }

      const ctr = globe.controls();
      ctr.enableZoom = false;
      ctr.enablePan = false;

      const fixedPolar = typeof ctr.getPolarAngle === 'function' ? ctr.getPolarAngle() : Math
        .PI / 2;
      ctr.minPolarAngle = fixedPolar;
      ctr.maxPolarAngle = fixedPolar;

      ctr.autoRotate = true;
      ctr.autoRotateSpeed = 2;

      function onResize() {
        globe.width(container.offsetWidth).height(container.offsetHeight);
      }
      window.addEventListener('resize', onResize);
    }
  });
}

function initLottieAutoplay() {
  document.querySelectorAll('[data-json][play="true"]').forEach(lottieEl => {
    lottie.loadAnimation({
      container: lottieEl,
      renderer: 'svg',
      loop: true,
      autoplay: true,
      path: lottieEl.getAttribute('data-json')
    });
  });
}

function initTFTLjson() {
  document.querySelectorAll('.credits').forEach(trigger => {
    const lottieEl = trigger.querySelector('.tftl-lottie');
    if (!lottieEl) return;

    const anim = lottie.loadAnimation({
      container: lottieEl,
      renderer: 'svg',
      loop: false,
      autoplay: false,
      path: lottieEl.getAttribute('data-json')
    });

    anim.goToAndStop(0, true);

    const totalFrames = 99;
    const tl = gsap.timeline({ paused: true });

    tl.to({ p: 0 }, {
      p: 1,
      duration: 1,
      ease: "none",
      onUpdate: function () {
        const frame = Math.round(this.targets()[0].p * (totalFrames - 1));
        anim.goToAndStop(frame, true);
      }
    });

    trigger.addEventListener('mouseenter', () => {
      gsap.to(tl, { progress: 0.5, duration: 1 });
    });

    trigger.addEventListener('mouseleave', () => {
      gsap.to(tl, { progress: 1, duration: 1 });
    });
  });
}

// CMS

function initBenefitsAccordion() {
  const buttons = Array.from(document.querySelectorAll('[benefits-btn]'))
  if (!buttons.length) return

  let zTop = 1
  let activeId = null
  let refreshDC = null

  function getParts(id) {
    return {
      desc: document.querySelector(`[benefits-desc="${id}"]`),
      media: document.querySelector(`[benefits-media-item="${id}"]`),
      imgW: document.querySelector(`[benefits-img-w="${id}"]`),
      img: document.querySelector(`[benefits-img="${id}"]`),
      icon2: document.querySelector(`[benefits-icon-2="${id}"]`)
    }
  }

  function bringToFront(el) {
    zTop += 1
    el.style.zIndex = String(zTop)
  }

  function openCard(id) {
    const { desc, media, imgW, img, icon2 } = getParts(id)

    gsap.killTweensOf([desc, media, imgW, img, icon2])
    killTextReveal(id);

    bringToFront(media)

    gsap.set(desc, { height: 0, overflow: 'hidden' })
    gsap.set(imgW, { yPercent: 100 })
    gsap.set(img, { yPercent: -50, scale: 2 })
    gsap.set(icon2, { rotate: 0 })

    gsap.to(desc, {
      height: 'auto',
      duration: 1,
      ease: 'Out',
      onComplete: initScrollTriggerRefresh
    })

    gsap.to(imgW, {
      yPercent: 0,
      duration: 1,
      ease: 'Out'
    })

    gsap.to(img, {
      yPercent: 0,
      scale: 1,
      duration: 1,
      ease: 'Out'
    })

    gsap.to(icon2, {
      rotate: 90,
      duration: 0.6,
      ease: 'InOut'
    })

    splitTextSetup(id)
    animateTextReveal(id, 'in')
    activeId = id
  }

  function closeCard(id) {
    const { desc, media, icon2 } = getParts(id)

    gsap.killTweensOf([desc, media, icon2])
    killTextReveal(id);

    gsap.to(desc, {
      height: 0,
      duration: 1,
      ease: 'Out',
      onComplete: initScrollTriggerRefresh
    })

    gsap.to(icon2, {
      rotate: 180,
      duration: 0.6,
      ease: 'InOut'
    })

    animateTextReveal(id, 'out')
    if (activeId === id) activeId = null
  }

  function closeActive() {
    if (activeId !== null) closeCard(activeId)
  }

  buttons.forEach(btn => {
    const id = btn.getAttribute('benefits-btn')
    const { desc, media } = getParts(id)
    if (!desc || !media) return

    btn.addEventListener('click', () => {
      if (activeId === id) {
        closeCard(id)
      } else {
        closeActive()
        openCard(id)
      }
    })
  })

  const firstId = buttons[0].getAttribute('benefits-btn')
  openCard(firstId)
}

function initLoopingWords() {
  ScrollTrigger.matchMedia({
    [`(min-width: ${breakPoint}px)`]: function () {
      const wordList = document.querySelector('[data-looping-words-list]');
      if (!wordList) return;

      const words = Array.from(wordList.children);
      const totalWords = words.length;
      if (totalWords < 5) return;

      const wordHeight = 100 / totalWords;
      let currentIndex = 5;

      gsap.set(wordList, { yPercent: -wordHeight * currentIndex });

      function setCurrent(index) {
        words.forEach(el => el.classList.remove('current'));
        const activeWord = words[index % totalWords];
        if (activeWord) activeWord.classList.add('current');
      }

      function moveWords() {
        const nextIndex = currentIndex + 1;

        setCurrent(nextIndex);

        gsap.to(wordList, {
          yPercent: -wordHeight * nextIndex,
          duration: 0.6,
          ease: 'Out',
          onComplete: function () {
            currentIndex = nextIndex;

            if (currentIndex >= totalWords - 6) {
              wordList.appendChild(wordList.children[0]);
              currentIndex--;
              gsap.set(wordList, { yPercent: -wordHeight * currentIndex });
              words.push(words.shift());
            }
          }
        });
      }

      setCurrent(currentIndex);

      gsap.timeline({ repeat: -1, delay: 0 })
        .call(moveWords)
        .to({}, { duration: 0.8 });
    }
  });

  ScrollTrigger.matchMedia({
    [`(max-width: ${breakPoint - 1}px)`]: function () {
      const wordList = document.querySelector('[data-looping-words-list]');
      if (!wordList) return;

      const words = Array.from(wordList.children);
      const totalWords = words.length;
      if (totalWords < 5) return;

      let wordWidth = words[0]?.getBoundingClientRect().width || 0;
      let currentIndex = 5;

      function setXByIndex(i) {
        gsap.set(wordList, { x: -wordWidth * i });
      }

      function setCurrent(index) {
        words.forEach(el => el.classList.remove('current'));
        const activeWord = words[index % totalWords];
        if (activeWord) activeWord.classList.add('current');
      }

      setXByIndex(currentIndex);
      setCurrent(currentIndex);

      function moveWords() {
        const nextIndex = currentIndex + 1;

        setCurrent(nextIndex);

        gsap.to(wordList, {
          x: -wordWidth * nextIndex,
          duration: 1,
          ease: 'Out',
          onComplete: () => {
            currentIndex = nextIndex;

            if (currentIndex >= totalWords - 6) {
              wordList.appendChild(wordList.children[0]);
              currentIndex--;
              setXByIndex(currentIndex);
              words.push(words.shift());
            }
          }
        });
      }

      gsap.timeline({ repeat: -1, delay: 0 })
        .call(moveWords)
        .to({}, { duration: 1.2 });

      window.addEventListener('resize', () => {
        const w = words[0]?.getBoundingClientRect().width || 0;
        if (!w) return;
        wordWidth = w;
        setXByIndex(currentIndex);
      });
    }
  });
}

// Other

function initOther() {
  // Current year
  const els = document.querySelectorAll('.year');
  if (!els.length) return;

  const year = new Date().getFullYear();
  els.forEach(el => {
    el.textContent = year;
  });

  // Data sqm superscript
  document.querySelectorAll('[data-sqm]').forEach(el => {
    el.innerHTML = el.innerHTML.replace(/([mMмМ])([2-4])/g, (match, letter, digit) => {
      return letter + '<sup>' + digit + '</sup>';
    });
  });

  // Form button
  document.querySelectorAll('[data-form-btn]').forEach(btn => {
    btn.addEventListener('click', e => {
      e.preventDefault();
      const form = btn.closest('form');
      if (form) form.requestSubmit();
    });
  });
}

function initFormSuccessToggle() {
  const success = document.querySelector('.pop-up_cta_form-block_success')
  const closeBtn = document.querySelector('.btn-cta-close_c')
  if (!success || !closeBtn) return

  function sync() {
    const visible = getComputedStyle(success).display !== 'none'
    closeBtn.style.display = visible ? 'none' : ''
  }

  sync()

  const mo = new MutationObserver(sync)
  mo.observe(success, { attributes: true, attributeFilter: ['style', 'class'] })
}

function initFlickerShow() {
  ScrollTrigger.matchMedia({
    [`(max-width: ${breakPoint - 1}px)`]: function () {
      document.querySelectorAll("[data-prevent-flicker='true']").forEach(text => {
        gsap.set(text, { visibility: "visible" });
      });
    }
  });
}

function initResetWebflow(data) {
  // Reset Webflow
  let parser = new DOMParser();
  let dom = parser.parseFromString(data.next.html, "text/html");
  let webflowPageId = dom.querySelector("html").getAttribute("data-wf-page");
  document.documentElement.setAttribute("data-wf-page", webflowPageId);
  window.Webflow.destroy();
  window.Webflow.ready();
  // window.Webflow.require("ix2").init();
}

function hideLocal(root = document) {
  const segs = location.pathname
    .split("?")[0]
    .replace(/\/+$/, "")
    .split("/")
    .filter(Boolean)
    .map(s => decodeURIComponent(s).toLowerCase());
  if (!segs.length) return;

  root.querySelectorAll("[local]").forEach(el => {
    const raw = (el.getAttribute("local") || "").trim();
    if (!raw) return;
    const parts = raw
      .replace(/^\/*|\/*$/g, "")
      .split("/")
      .filter(Boolean)
      .map(s => s.toLowerCase());
    if (!parts.length) return;

    let match = false;
    if (parts.length === 1) {
      match = segs.includes(parts[
        0]);
    } else {
      for (let i = 0; i <= segs.length - parts.length && !match; i++) {
        match = parts.every((p, k) => p === segs[i + k]);
      }
    }
    if (match) el.style.display = "none";
  });
}

